# MFA enrollment requires user interaction.
# Use SCP to enforce MFA:
resource "aws_organizations_policy" "require_mfa" {
  name    = "RequireMFA"
  content = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Sid       = "DenyWithoutMFA"
      Effect    = "Deny"
      Action    = "*"
      Resource  = "*"
      Condition = {
        BoolIfExists = {
          "aws:MultiFactorAuthPresent" = "false"
        }
      }
    }]
  })
}
